241→fn authorizeChallenge(
242→    flow_ctx: *orchestration.FlowContext,
243→    runtime_config: *const acme_types.RuntimeConfig,
244→    acme_client: *Client,
245→    signer: *const signer_mod.AccountSigner,
246→    io: Io,
247→    work: WorkBuffers,
248→    auth_url: *const client.Url,
249→    hook_provider: *tls_alpn_hook_mod.TlsAlpnHookProvider,
250→) Error!void {
251→    const auth = try fetchAuthorization(flow_ctx, acme_client, signer, io, work, auth_url);
252→    if (auth.status == .valid) return;
253→
254→    const host = auth.identifier_dns.slice();
255→
256→    const challenge = auth.firstTlsAlpn01Challenge() orelse return error.MissingTlsAlpn01Challenge;
257→    return try authorizeTlsAlpn01(
258→        flow_ctx,
259→        runtime_config,
260→        acme_client,
261→        signer,
262→        io,
263→        work,
264→        auth_url,
265→        host,
266→        challenge,
267→        hook_provider,
268→    );
