283→    var key_auth_buf: [config.ACME_MAX_HTTP01_KEY_AUTHORIZATION_BYTES]u8 = undefined;
284→    const key_auth = try signer.computeKeyAuthorization(challenge.token(), &key_auth_buf);
285→
286→    var cert_pem_buf: [8192]u8 = undefined;
287→    var key_pem_buf: [4096]u8 = undefined;
288→    const materials = try tls_alpn_cert_mod.generateMaterials(io, host, key_auth, &cert_pem_buf, &key_pem_buf);
289→
290→    const state_dir = runtime_config.stateDirPath();
291→
292→    var cert_path_buf: [1024]u8 = undefined;
293→    var key_path_buf: [1024]u8 = undefined;
294→    const cert_path = std.fmt.bufPrint(&cert_path_buf, "{s}/tls-alpn-challenge-cert.pem", .{state_dir}) catch return error.InvalidRuntimeConfig;
295→    const key_path = std.fmt.bufPrint(&key_path_buf, "{s}/tls-alpn-challenge-key.pem", .{state_dir}) catch return error.InvalidRuntimeConfig;
296→
297→    const cwd = Io.Dir.cwd();
298→    cwd.createDirPath(std.Options.debug_io, state_dir) catch return error.InvalidRuntimeConfig;
299→    cwd.writeFile(std.Options.debug_io, .{ .sub_path = cert_path, .data = materials.cert_pem }) catch return error.InvalidRuntimeConfig;
300→    cwd.writeFile(std.Options.debug_io, .{ .sub_path = key_path, .data = materials.key_pem }) catch return error.InvalidRuntimeConfig;
